// Tenant slug sent by the dashboard
const tenantSlug = $('Webhook').first().json.body?.tenant_slug || '';

const rows = $input.all().map(i => i.json);

const filtered = rows.filter(row => {
  if (!tenantSlug) return true;
  const slug = (row['tenant_slug'] || row['Tenant Slug'] || row['tenant'] || '').toLowerCase();
  return !slug || slug === tenantSlug.toLowerCase();
});

const result = filtered.slice(-200).reverse().map(row => ({
  message_id:   row['message_id']   || row['Message ID'] || row['id']          || '',
  phone_number: row['phone_number'] || row['Phone']      || row['from']        || row['to']      || '—',
  channel:      (row['channel']     || row['Channel']    || row['type']        || 'sms').toLowerCase(),
  direction:    (row['direction']   || row['Direction']  || 'inbound').toLowerCase(),
  content:      row['content']      || row['Content']    || row['message']     || row['body']    || row['text'] || '',
  ai_reply:     row['ai_reply']     || row['AI Reply']   || row['response']    || row['ai_response'] || '',
  status:       row['status']       || row['Status']     || 'delivered',
  sent_at:      row['sent_at']      || row['Sent At']    || row['timestamp']   || row['created_at'] || row['Date'] || '',
  tenant_slug:  row['tenant_slug']  || row['Tenant Slug']|| tenantSlug
}));

return [{ json: { result } }];
